<?php session_start(); require 'includes/header.php'; require_login(); if(role()!='Administrator'){ echo '<h1>Access denied</h1>'; require 'includes/footer.php'; exit; } if($_SERVER['REQUEST_METHOD']==='POST'){ $pdo->prepare('INSERT INTO users(full_name,email,password,role_id,department,status) VALUES(?,?,?,?,?,?)')->execute([$_POST['full_name'],$_POST['email'],password_hash($_POST['password'],PASSWORD_DEFAULT),$_POST['role_id'],$_POST['department'],$_POST['status']]); header('Location:users.php'); exit; } $roles=$pdo->query('SELECT * FROM roles')->fetchAll(); $rows=$pdo->query('SELECT u.*,r.name role FROM users u JOIN roles r ON r.id=u.role_id ORDER BY u.full_name')->fetchAll(); ?><h1>Users</h1><div class="card"><form method="post" class="formgrid"><input name="full_name" placeholder="Full Name" required><input name="email" type="email" placeholder="Email" required><input name="password" type="password" placeholder="Password" required><select name="role_id"><?php foreach($roles as $r) echo '<option value="'.$r['id'].'">'.e($r['name']).'</option>'; ?></select><input name="department" placeholder="Department"><select name="status"><option>active</option><option>disabled</option></select><button>Create User</button></form></div><div class="card"><table><tr><th>Name</th><th>Email</th><th>Role</th><th>Department</th><th>Status</th></tr><?php foreach($rows as $r): ?><tr><td><?=e($r['full_name'])?></td><td><?=e($r['email'])?></td><td><?=e($r['role'])?></td><td><?=e($r['department'])?></td><td><?=e($r['status'])?></td></tr><?php endforeach ?></table></div><?php require 'includes/footer.php'; ?>
